import React, { useState, useRef } from 'react';
import emailjs from '@emailjs/browser';

function Contact() {
  const formRef = useRef();
  const [form, setForm] = useState({ nom: '', email: '', sujet: '', message: '' });
  const [envoye, setEnvoye] = useState(false);
  const [erreur, setErreur] = useState(false);
  const [loading, setLoading] = useState(false);
  const [focused, setFocused] = useState(null);

  const handleChange = (e) => setForm({ ...form, [e.target.name]: e.target.value });

  const handleSubmit = (e) => {
    e.preventDefault();
    setLoading(true);
    emailjs.sendForm(
      'service_23jlrir',
      'y03ivur',
      formRef.current,
      'WUp9An2JvFkFWqfJ3'
    ).then(() => {
      setEnvoye(true);
      setErreur(false);
      setForm({ nom: '', email: '', sujet: '', message: '' });
      setTimeout(() => setEnvoye(false), 4000);
    }).catch(() => {
      setErreur(true);
      setTimeout(() => setErreur(false), 4000);
    }).finally(() => setLoading(false));
  };

  const inputStyle = (name) => ({
    width: '100%', padding: '14px 16px', marginBottom: '16px',
    background: focused === name ? 'rgba(0,170,0,0.05)' : 'rgba(255,255,255,0.03)',
    border: `1px solid ${focused === name ? 'rgba(0,170,0,0.5)' : 'rgba(255,255,255,0.08)'}`,
    borderRadius: '10px', color: '#e8e8e8', fontSize: '0.95rem',
    fontFamily: "'Rajdhani', sans-serif", outline: 'none', boxSizing: 'border-box',
    transition: 'all 0.3s',
    boxShadow: focused === name ? '0 0 15px rgba(0,170,0,0.1)' : 'none'
  });

  return (
    <div style={{ background: '#050505', minHeight: '100vh', paddingTop: '70px' }}>
      <style>{`
        @keyframes successPop { 0% { transform: scale(0.8); opacity: 0; } 100% { transform: scale(1); opacity: 1; } }
        .contact-info-card { display: flex; gap: 16px; align-items: flex-start; background: rgba(255,255,255,0.02); border: 1px solid rgba(0,170,0,0.12); border-radius: 14px; padding: 20px; margin-bottom: 14px; transition: all 0.3s; cursor: default; }
        .contact-info-card:hover { border-color: rgba(0,170,0,0.35); transform: translateX(8px); background: rgba(0,170,0,0.04); }
        .btn-submit { width: 100%; padding: 16px; background: linear-gradient(135deg, #00aa00, #007700); color: #fff; border: none; border-radius: 10px; font-size: 1rem; font-weight: 700; cursor: pointer; font-family: 'Rajdhani', sans-serif; letter-spacing: 2px; text-transform: uppercase; transition: all 0.3s; position: relative; overflow: hidden; }
        .btn-submit:hover { transform: translateY(-2px); box-shadow: 0 8px 25px rgba(0,170,0,0.4); }
      `}</style>

      <section style={{ textAlign: 'center', padding: '80px 20px 60px', background: 'radial-gradient(ellipse at center, rgba(0,60,0,0.15) 0%, transparent 70%)', borderBottom: '1px solid rgba(0,170,0,0.1)' }}>
        <p style={{ color: '#00aa00', fontFamily: "'Rajdhani', sans-serif", letterSpacing: '4px', fontSize: '0.85rem', textTransform: 'uppercase', marginBottom: '12px' }}>— Travaillons ensemble —</p>
        <h1 style={{ fontFamily: "'Orbitron', sans-serif", fontSize: 'clamp(2rem, 5vw, 3.5rem)', color: '#ffd700', fontWeight: 900, letterSpacing: '3px', marginBottom: '16px' }}>Contact</h1>
        <p style={{ color: '#666', fontSize: '1.1rem', fontFamily: "'Rajdhani', sans-serif" }}>Parlons de votre projet informatique</p>
      </section>

      <section style={{ padding: '80px 40px', maxWidth: '1100px', margin: '0 auto' }}>
        <div style={{ display: 'grid', gridTemplateColumns: '1fr 1.4fr', gap: '40px' }}>

          <div>
            <h2 style={{ fontFamily: "'Orbitron', sans-serif", color: '#ffd700', fontSize: '1rem', marginBottom: '30px', letterSpacing: '2px' }}>Mes coordonnées</h2>
            {[
              { icon: '📍', titre: 'Localisation', info: 'Dakar, Sénégal\nQuartier Fass Delorme, 10500' },
              { icon: '📧', titre: 'Email', info: 'badjinaboussougourevesyndie@gmail.com' },
              { icon: '🕐', titre: 'Sur site — Dakar', info: 'Lundi — Vendredi : 08h00 - 18h00' },
              { icon: '🌐', titre: 'À distance', info: 'Lundi — Samedi : Disponible à toute heure' }
            ].map((item, i) => (
              <div key={i} className="contact-info-card">
                <span style={{ fontSize: '1.8rem', flexShrink: 0 }}>{item.icon}</span>
                <div>
                  <h3 style={{ color: '#00aa00', fontSize: '0.9rem', fontFamily: "'Rajdhani', sans-serif", fontWeight: 700, letterSpacing: '1px', marginBottom: '4px' }}>{item.titre}</h3>
                  <p style={{ color: '#777', fontSize: '0.85rem', fontFamily: "'Rajdhani', sans-serif", whiteSpace: 'pre-line', lineHeight: 1.6 }}>{item.info}</p>
                </div>
              </div>
            ))}
            <div style={{ marginTop: '24px', background: 'rgba(0,170,0,0.08)', border: '1px solid rgba(0,170,0,0.2)', borderRadius: '12px', padding: '16px', display: 'flex', alignItems: 'center', gap: '12px' }}>
              <div style={{ width: '10px', height: '10px', borderRadius: '50%', background: '#00aa00', boxShadow: '0 0 10px #00aa00', flexShrink: 0 }} />
              <span style={{ color: '#00aa00', fontFamily: "'Rajdhani', sans-serif", fontSize: '0.9rem', fontWeight: 700, letterSpacing: '1px' }}>Disponible pour de nouveaux projets</span>
            </div>
          </div>

          <div style={{ background: 'rgba(255,255,255,0.02)', border: '1px solid rgba(0,170,0,0.12)', borderRadius: '20px', padding: '40px' }}>
            <h2 style={{ fontFamily: "'Orbitron', sans-serif", color: '#ffd700', fontSize: '1rem', marginBottom: '30px', letterSpacing: '2px' }}>Envoyez un message</h2>
            {envoye && (
              <div style={{ background: 'rgba(0,170,0,0.1)', border: '1px solid rgba(0,170,0,0.3)', borderRadius: '10px', padding: '14px', textAlign: 'center', marginBottom: '20px', color: '#00aa00', fontFamily: "'Rajdhani', sans-serif", fontWeight: 700, animation: 'successPop 0.3s ease' }}>
                ✅ Message envoyé ! Je vous répondrai rapidement.
              </div>
            )}
            {erreur && (
              <div style={{ background: 'rgba(255,0,0,0.1)', border: '1px solid rgba(255,0,0,0.3)', borderRadius: '10px', padding: '14px', textAlign: 'center', marginBottom: '20px', color: '#ff4444', fontFamily: "'Rajdhani', sans-serif", fontWeight: 700, animation: 'successPop 0.3s ease' }}>
                ❌ Erreur lors de l'envoi. Réessayez !
              </div>
            )}
            <form ref={formRef} onSubmit={handleSubmit}>
              <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '0 16px' }}>
                {[{ name: 'nom', placeholder: 'Votre nom', type: 'text' }, { name: 'email', placeholder: 'Votre email', type: 'email' }].map(field => (
                  <input key={field.name} type={field.type} name={field.name} placeholder={field.placeholder} value={form[field.name]} onChange={handleChange} onFocus={() => setFocused(field.name)} onBlur={() => setFocused(null)} style={inputStyle(field.name)} required />
                ))}
              </div>
              <input type="text" name="sujet" placeholder="Sujet" value={form.sujet} onChange={handleChange} onFocus={() => setFocused('sujet')} onBlur={() => setFocused(null)} style={inputStyle('sujet')} required />
              <textarea name="message" placeholder="Décrivez votre projet..." value={form.message} onChange={handleChange} onFocus={() => setFocused('message')} onBlur={() => setFocused(null)} rows={5} style={{ ...inputStyle('message'), resize: 'vertical', minHeight: '130px' }} required />
              <button type="submit" className="btn-submit" disabled={loading}>
                {loading ? '⏳ Envoi en cours...' : '🚀 Envoyer le message'}
              </button>
            </form>
          </div>
        </div>
      </section>
    </div>
  );
}

export default Contact;
